final:
module top_module(
           input reset_clk ,
           input rst ,
           input en ,
           input [31: 0] PC_input ,
           output reg [31: 0] PC_output
       );always @(posedge reset_clk or posedge rst)
begin
    if (rst) PC_output <= 0;
    else if (en) PC_output <= PC_input;
    else PC_output <= PC_output;

end

endmodule
